<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8" />
    <title>Maze Game</title>
    <style>
        #maze {
            width: 400px;
            height: 400px;
            border: 1px solid black;
        }
        body {
            font-family: sans-serif;
        }
        #timer, #completed {
            margin-top: 10px;
        }
    </style>
</head>
<body>
    <div id="maze"></div>
    <div id="timer">Elapsed: 0</div>
    <div id="completed">Completed: 0/24</div>
    <button id="reset">Reset</button>

    <script>
        function createSeededRandom(seed) {
            return () => {
                const m = 0x100000000;
                const a = 1103515245;
                const c = 12345;
                seed = (a * seed + c) % m;
                return seed / m; // [0,1)
            };
        }

        function generateMaze(rows, cols, seed) {
            const walls = [];
            for (let r = 0; r < rows; r++) {
                walls[r] = [];
                for (let c = 0; c < cols; c++) {
                    walls[r][c] = {n: true, e: true, s: true, w: true};
                }
            }

            const visited = new Set();
            const stack = [];

            // Start at a random cell
            const rand = createSeededRandom(seed);
            let r = Math.floor(rand() * rows);
            let c = Math.floor(rand() * cols);
            stack.push({r, c});
            visited.add(`${r},${c}`);

            while (stack.length > 0) {
                const current = stack[stack.length - 1];
                const directions = [{dr: -1, dc: 0}, {dr: 0, dc: 1}, {dr: 1, dc: 0}, {dr: 0, dc: -1}]; // N, E, S, W
                let unvisitedNeighbors = [];

                for (const dir of directions) {
                    const nr = current.r + dir.dr;
                    const nc = current.c + dir.dc;
                    if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !visited.has(`${nr},${nc}`)) {
                        unvisitedNeighbors.push({dir, nr, nc});
                    }
                }

                if (unvisitedNeighbors.length > 0) {
                    // Choose a random unvisited neighbor
                    const index = Math.floor(rand() * unvisitedNeighbors.length);
                    const chosen = unvisitedNeighbors[index];
                    const {dir, nr, nc} = chosen;

                    // Knock down the wall between current and new cell
                    if (dir.dr === -1) {
                        walls[current.r][current.c].n = false;
                        walls[nr][nc].s = false;
                    } else if (dir.dc === 1) {
                        walls[current.r][current.c].e = false;
                        walls[nr][nc].w = false;
                    } else if (dir.dr === 1) {
                        walls[current.r][current.c].s = false;
                        walls[nr][nc].n = false;
                    } else if (dir.dc === -1) {
                        walls[current.r][current.c].w = false;
                        walls[nr][nc].e = false;
                    }

                    visited.add(`${nr},${nc}`);
                    stack.push({r: nr, c: nc});
                } else {
                    // Backtrack
                    stack.pop();
                }
            }

            return walls;
        }

        const game = {
            size: {rows: 15, cols: 15},
            spawn: {r: 0, c: 0},
            exit: null,
            wallsData: [],
            bots: [],
            elapsed: 0,
            lastFinishTick: Infinity,

            reset(seed) {
                this.size.rows = 15;
                this.size.cols = 15;
                this.spawn.r = 0;
                this.spawn.c = 0;

                // Generate maze
                const wallsData = generateMaze(this.size.rows, this.size.cols, seed || Math.random());
                this.wallsData = wallsData;

                // Choose exit cell
                let exitSeed = seed ? seed + 1 : Math.random();
                const randExit = createSeededRandom(exitSeed);
                let exitR = Math.floor(randExit() * this.size.rows);
                let exitC = Math.floor(randExit() * this.size.cols);
                while (exitR === this.spawn.r && exitC === this.spawn.c) {
                    exitR = Math.floor(randExit() * this.size.rows);
                    exitC = Math.floor(randExit() * this.size.cols);
                }
                this.exit = {r: exitR, c: exitC};

                // Initialize bots
                this.bots = [];
                for (let i = 0; i < 24; i++) {
                    const botSeed = seed ? seed + 2 + i : Math.random();
                    const directionOrder = this.generateDirectionOrder(botSeed);
                    this.bots.push({
                        path: [{r: this.spawn.r, c: this.spawn.c}],
                        visitedCells: new Set([`${this.spawn.r},${this.spawn.c}`]),
                        deadEnds: [],
                        finishTick: null,
                        directions: directionOrder
                    });
                }

                this.elapsed = 0;
                this.lastFinishTick = Infinity;
            },

            generateDirectionOrder(seed) {
                const dirs = ['n', 'e', 's', 'w'];
                // Shuffle using Fisher-Yates with seeded random
                const rand = createSeededRandom(seed);
                for (let i = dirs.length - 1; i > 0; i--) {
                    const j = Math.floor(rand() * (i + 1));
                    [dirs[i], dirs[j]] = [dirs[j], dirs[i]];
                }
                return dirs;
            },

            tick(n) {
                for (let step = 0; step < n; step++) {
                    const activeBots = this.bots.filter(bot => !bot.finishTick);
                    if (activeBots.length === 0) break;

                    for (const bot of activeBots) {
                        // Process movement
                        const current = bot.path[bot.path.length - 1];
                        let nextCell = null;
                        let directionFound = false;

                        // Check all four directions in preference order
                        for (const dir of bot.directions) {
                            let newR, newC;
                            if (dir === 'n') { newR = current.r - 1; newC = current.c; }
                            else if (dir === 'e') { newR = current.r; newC = current.c + 1; }
                            else if (dir === 's') { newR = current.r + 1; newC = current.c; }
                            else if (dir === 'w') { newR = current.r; newC = current.c - 1; }

                            // Check bounds
                            if (newR < 0 || newR >= this.size.rows || newC < 0 || newC >= this.size.cols) continue;

                            // Check wall in this direction
                            const hasWall = !this.walls(current.r, current.c)[dir];
                            if (hasWall) continue;

                            // Check if adjacent cell is already visited by this bot
                            const key = `${newR},${newC}`;
                            if (!bot.visitedCells.has(key)) {
                                nextCell = {r: newR, c: newC};
                                directionFound = true;
                                break;
                            }
                        }

                        // If no unvisited directions found, backtrack
                        if (!directionFound && bot.path.length > 1) {
                            // Pop the last cell from path (backtrack)
                            nextCell = bot.path[bot.path.length - 2];
                        } else if (!directionFound && bot.path.length === 1) {
                            // Dead end and at spawn. No more backtracking.
                            continue;
                        }

                        if (nextCell) {
                            const key = `${nextCell.r},${nextCell.c}`;
                            bot.visitedCells.add(key);
                            bot.path.push(nextCell);

                            // Check if this new cell is the exit
                            if (nextCell.r === this.exit.r && nextCell.c === this.exit.c) {
                                bot.finishTick = this.elapsed + 1;
                                if (bot.finishTick > this.lastFinishTick) {
                                    this.lastFinishTick = bot.finishTick;
                                }
                            } else {
                                // Update lastFinishTick only if it's not already set
                                if (!this.lastFinishTick || this.lastFinishTick === Infinity) {
                                    this.lastFinishTick = Infinity; // Placeholder, will be updated when a bot finishes
                                }
                            }
                        }
                    }

                    this.elapsed++;
                }

                // After processing ticks, check if all bots have finished and freeze elapsed at last finish tick
                const allFinished = this.bots.every(bot => bot.finishTick !== null);
                if (allFinished) {
                    this.elapsed = Math.min(this.elapsed, this.lastFinishTick);
                }
            },

            walls(r, c) {
                return {n: this.wallsData[r][c].n, e: this.wallsData[r][c].e, s: this.wallsData[r][c].s, w: this.wallsData[r][c].w};
            }
        };

        function drawMaze(ctx, game) {
            const rows = game.size.rows;
            const cols = game.size.cols;
            const canvasSize = 400;
            const cellSize = Math.min(canvasSize / rows, canvasSize / cols);
            ctx.clearRect(0, 0, canvasSize, canvasSize);

            for (let r = 0; r < rows; r++) {
                for (let c = 0; c < cols; c++) {
                    const x = c * cellSize;
                    const y = r * cellSize;

                    // Draw north wall
                    if (game.walls(r, c).n) {
                        ctx.beginPath();
                        ctx.moveTo(x, y);
                        ctx.lineTo(x + cellSize, y);
                        ctx.stroke();
                    }

                    // Draw east wall
                    if (game.walls(r, c).e) {
                        ctx.beginPath();
                        ctx.moveTo(x + cellSize, y);
                        ctx.lineTo(x + cellSize, y + cellSize);
                        ctx.stroke();
                    }

                    // Draw south wall
                    if (game.walls(r, c).s) {
                        ctx.beginPath();
                        ctx.moveTo(x, y + cellSize);
                        ctx.lineTo(x + cellSize, y + cellSize);
                        ctx.stroke();
                    }

                    // Draw west wall
                    if (game.walls(r, c).w) {
                        ctx.beginPath();
                        ctx.moveTo(x, y);
                        ctx.lineTo(x, y + cellSize);
                        ctx.stroke();
                    }
                }
            }
        }

        function drawBots(ctx, game) {
            const rows = game.size.rows;
            const cols = game.size.cols;
            const canvasSize = 400;
            const cellSize = Math.min(canvasSize / rows, canvasSize / cols);

            // Generate distinct colors for bots
            const colors = ['#f00', '#0f0', '#00f', '#ff0', '#0ff', '#f0f', 
                            '#9932cc', '#8b4513', '#a52a2a', '#deb887', '#5f9ea0', '#7fff00',
                            '#d2691e', '#ff7f50', '#6495ed', '#dc143c', '#00ffff', '#0000cd',
                            '#ba55d3', '#cd5c5c', '#ffa500', '#4b0082'];
            for (let i = 0; i < game.bots.length; i++) {
                const bot = game.bots[i];
                if (bot.finishTick !== null) continue;

                const path = bot.path;
                let pos = {x: 0, y: 0};

                // If only one cell in path
                if (path.length === 1) {
                    const r = path[0].r;
                    const c = path[0].c;
                    pos.x = c * cellSize + cellSize / 2;
                    pos.y = r * cellSize + cellSize / 2;
                } else {
                    // Interpolate between last two cells
                    const prevCell = path[path.length - 2];
                    const currCell = path[path.length - 1];

                    const px0 = prevCell.c * cellSize + cellSize / 2;
                    const py0 = prevCell.r * cellSize + cellSize / 2;
                    const px1 = currCell.c * cellSize + cellSize / 2;
                    const py1 = currCell.r * cellSize + cellSize / 2;

                    // Assume halfway between cells
                    pos.x = (px0 + px1) / 2;
                    pos.y = (py0 + py1) / 2;
                }

                ctx.fillStyle = colors[i % colors.length];
                ctx.beginPath();
                ctx.arc(pos.x, pos.y, cellSize / 6, 0, Math.PI * 2);
                ctx.fill();
            }
        }

        window.onload = function() {
            const canvas = document.getElementById('maze');
            const ctx = canvas.getContext('2d');
            canvas.width = 400;
            canvas.height = 400;

            // Initialize game
            game.reset(); // default seed

            // Update UI elements
            function updateUI() {
                document.getElementById('timer').textContent = 'Elapsed: ' + game.elapsed;
                const completedCount = game.bots.filter(bot => bot.finishTick !== null).length;
                document.getElementById('completed').textContent = `Completed: ${completedCount}/24`;
            }

            // Rendering loop
            function render() {
                drawMaze(ctx, game);
                drawBots(ctx, game);
                requestAnimationFrame(render);
            }
            render();

            // Reset button handler
            document.getElementById('reset').addEventListener('click', () => {
                game.reset();
                updateUI();
            });

            // Expose game API to window for automated grading
            window.game = game;
        };
    </script>
</body>
