<!DOCTYPE html>
<html>
<head>
<style>
  body {
    font-family: sans-serif;
    text-align: center;
  }
  #completed, #timer {
    margin: 10px;
    font-size: 24px;
  }
  canvas {
    border: 1px solid black;
    image-rendering: crisp-edges;
  }
</style>
</head>
<body>
<div id="completed">0/24</div>
<div id="timer">0</div>
<button id="reset">Reset</button>
<canvas id="maze" width="400" height="400"></canvas>

<script>
class XorShift {
  constructor(seed) {
    this.x = seed ^ 123456789;
    this.y = 309624123 ^ seed;
    this.z = this.x >> 1;
    this.w = this.y >> 1;
  }
  next() {
    let t = this.x ^ (this.x << 11);
    this.x = this.y;
    this.y = this.z;
    this.z = this.w;
    return this.w = (this.w ^ (this.w >>> 19)) ^ (t ^ (t >>> 8));
  }
  nextInt(max) {
    return Math.floor(this.next() / 0x100000000 * max);
  }
}

const game = {
  size: { rows: 15, cols: 15 },
  spawn: { r: 7, c: 7 },
  exit: null,
  walls: [],
  bots: [],
  elapsed: 0,
  lastFinishTick: null,
  completedCount: 0,
  isFrozen: false,

  init(seed) {
    const prng = new XorShift(seed);
    this.size.rows = Math.max(15, 20 + prng.nextInt(3));
    this.size.cols = Math.max(15, 20 + prng.nextInt(3));

    // Generate maze
    const rows = this.size.rows;
    const cols = this.size.cols;
    this.walls = Array.from({ length: rows }, () => 
      Array(cols).fill().map(() => ({ n: true, e: true, s: true, w: true }))
    );

    const visited = Array(rows).fill(false).map(() => Array(cols).fill(false));

    function carvePassages(r, c) {
      visited[r][c] = true;
      let dirs = ['n', 'e', 's', 'w'];
      while (dirs.length > 0) {
        const i = prng.nextInt(dirs.length);
        const dir = dirs.splice(i, 1)[0];
        let nr = r, nc = c;
        switch(dir) {
          case 'n': nr = r - 1; break;
          case 'e': nc = c + 1; break;
          case 's': nr = r + 1; break;
          case 'w': nc = c - 1; break;
        }
        if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !visited[nr][nc]) {
          switch(dir) {
            case 'n': game.walls[r][c].n = false; game.walls[nr][c].s = false; break;
            case 'e': game.walls[r][c].e = false; game.walls[r][nc].w = false; break;
            case 's': game.walls[r][c].s = false; game.walls[nr][c].n = false; break;
            case 'w': game.walls[r][c].w = false; game.walls[r][nc].e = false; break;
          }
          carvePassages(nr, nc);
        }
      }
    }

    let startR = prng.nextInt(rows);
    let startC = prng.nextInt(cols);
    this.spawn.r = startR;
    this.spawn.c = startC;
    carvePassages(startR, startC);

    // Place exit
    do {
      this.exit = { r: prng.nextInt(rows), c: prng.nextInt(cols) };
    } while (this.exit.r === this.spawn.r && this.exit.c === this.spawn.c);

    // Initialize bots
    this.bots = [];
    for (let i = 0; i < 24; i++) {
      const botSeed = seed * 100 + i;
      const dirs = ['n', 'e', 's', 'w'];
      const prngBot = new XorShift(botSeed);
      let shuffled = [...dirs];
      for (let j = shuffled.length - 1; j > 0; j--) {
        const k = prngBot.nextInt(j + 1);
        [shuffled[j], shuffled[k]] = [shuffled[k], shuffled[j]];
      }
      this.bots.push({
        path: [{ r: this.spawn.r, c: this.spawn.c }],
        edgesTraversals: new Map(),
        preferenceOrder: shuffled,
        finishTick: null
      });
    }

    this.elapsed = 0;
    this.lastFinishTick = null;
    this.completedCount = 0;
    this.isFrozen = false;

    draw();
  },

  tick(n) {
    if (this.isFrozen) return;
    for (let i = 0; i < n; i) {
      let allFinished = true;
      for (const bot of this.bots) {
        if (!bot.finishTick) {
          allFinished = false;
          break;
        }
      }
      if (allFinished) break;

      const newElapsed = this.elapsed + 1;
      const botsToFinishThisTick = [];

      for (let j = 0; j < this.bots.length; j++) {
        const bot = this.bots[j];
        if (bot.finishTick !== null) continue;

        const currentCell = bot.path[bot.path.length - 1];

        // Check if at exit
        if (currentCell.r === this.exit.r && currentCell.c === this.exit.c) {
          botsToFinishThisTick.push(bot);
          continue;
        }

        let foundNext = false;
        for (const dir of bot.preferenceOrder) {
          const { r: cr, c: cc } = currentCell;
          if (this.walls[cr][cc][dir]) continue;

          let nr = cr, nc = cc;
          switch(dir) {
            case 'n': nr--; break;
            case 's': nr++; break;
            case 'e': nc++; break;
            case 'w': nc--; break;
          }

          const nextCell = { r: nr, c: nc };
          const key = `${Math.min(cr, nr)}-${Math.min(cc, nc)}-${Math.max(cr, nr)}-${Math.max(cc, nc)}`;
          if (bot.edgesTraversals.get(key) !== undefined && bot.edgesTraversals.get(key) >= 2) continue;

          // Move to next cell
          bot.path.push(nextCell);
          bot.edgesTraversals.set(key, (bot.edgesTraversals.get(key) || 0) + 1);

          foundNext = true;
          break;
        }

        if (!foundNext) {
          // Backtrack
          while (bot.path.length > 1) {
            const prevCell = bot.path[bot.path.length - 2];
            const currentCell = bot.path[bot.path.length - 1];

            let dirToPrev;
            if (prevCell.r === currentCell.r - 1) dirToPrev = 's';
            else if (prevCell.r === currentCell.r + 1) dirToPrev = 'n';
            else if (prevCell.c === currentCell.c - 1) dirToPrev = 'e';
            else if (prevCell.c === currentCell.c + 1) dirToPrev = 'w';

            const keyBacktrack = `${Math.min(prevCell.r, currentCell.r)}-${Math.min(prevCell.c, currentCell.c)}-${Math.max(prevCell.r, currentCell.r)}-${Math.max(prevCell.c, currentCell.c)}`;
            if (bot.edgesTraversals.get(keyBacktrack) !== undefined && bot.edgesTraversals.get(keyBacktrack) < 2) {
              bot.path.pop();
              bot.edgesTraversals.set(keyBacktrack, (bot.edgesTraversals.get(keyBacktrack) || 0) + 1);
              break;
            } else {
              bot.path.pop();
            }
          }
        }
      }

      // Check for bots that reached exit this tick
      for (const bot of botsToFinishThisTick) {
        bot.finishTick = newElapsed;
        game.completedCount++;
        if (!game.lastFinishTick || newElapsed > game.lastFinishTick) {
          game.lastFinishTick = newElapsed;
        }
      }

      this.elapsed = newElapsed;

      // Check if all bots finished
      let allDone = true;
      for (const bot of this.bots) {
        if (bot.finishTick === null) {
          allDone = false;
          break;
        }
      }
      if (allDone) {
        game.isFrozen = true;
      }

      i++;
    }

    document.getElementById('completed').textContent = `${game.completedCount}/24`;
    document.getElementById('timer').textContent = game.elapsed;
  },

  reset(seed) {
    this.init(seed);
    draw();
  }
};

function draw() {
  const canvas = document.getElementById('maze');
  const ctx = canvas.getContext('2d');
  const rows = game.size.rows;
  const cols = game.size.cols;

  const cellWidth = canvas.width / cols;
  const cellHeight = canvas.height / rows;

  // Draw maze
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  for (let r = 0; r < rows; r++) {
    for (let c = 0; c < cols; c++) {
      const wall = game.walls[r][c];
      if (wall.n) {
        ctx.beginPath();
        ctx.moveTo(c * cellWidth, r * cellHeight);
        ctx.lineTo((c + 1) * cellWidth, r * cellHeight);
        ctx.stroke();
      }
      if (wall.e) {
        ctx.beginPath();
        ctx.moveTo((c + 1) * cellWidth, r * cellHeight);
        ctx.lineTo((c + 1) * cellWidth, (r + 1) * cellHeight);
        ctx.stroke();
      }
      if (wall.s) {
        ctx.beginPath();
        ctx.moveTo(c * cellWidth, (r + 1) * cellHeight);
        ctx.lineTo((c + 1) * cellWidth, (r + 1) * cellHeight);
        ctx.stroke();
      }
      if (wall.w) {
        ctx.beginPath();
        ctx.moveTo(c * cellWidth, r * cellHeight);
        ctx.lineTo(c * cellWidth, (r + 1) * cellHeight);
        ctx.stroke();
      }
    }
  }

  // Draw exit
  const exit = game.exit;
  ctx.fillStyle = 'red';
  ctx.fillRect(exit.c * cellWidth + cellWidth / 4, 
               exit.r * cellHeight + cellHeight / 4,
               cellWidth / 2, cellHeight / 2);

  // Draw bots
  for (let i = 0; i < game.bots.length; i++) {
    const bot = game.bots[i];
    if (bot.finishTick !== null) continue;

    const currentCell = bot.path[bot.path.length - 1];
    ctx.fillStyle = `hsl(${i * 15}, 70%, 60%)`;
    ctx.beginPath();
    ctx.arc(
      (currentCell.c + 0.5) * cellWidth,
      (currentCell.r + 0.5) * cellHeight,
      cellWidth / 8,
      0, Math.PI * 2
    );
    ctx.fill();
  }
}

document.getElementById('reset').addEventListener('click', () => {
  const seed = parseInt(prompt("Enter seed (optional):") || Date.now());
  game.reset(seed);
});

// Initialize with default seed
game.init(123456789);
</script>
</body>
</html>
